const ICON_SUCCESS="check",RESET_MS=1200;function getCopyText(e){if(e.dataset.copyTarget)return document.querySelector(e.dataset.copyTarget)?.textContent?.trim()||"";const t=e.closest("[data-copy]")||e.parentElement?.querySelector("[data-copy]");return t?t.getAttribute("href")||t.textContent.trim():""}function fallbackCopy(e){const t=document.createElement("textarea");t.value=e,t.style.position="fixed",t.style.opacity="0",t.style.pointerEvents="none",document.body.appendChild(t),t.select();const o=document.execCommand("copy");return t.remove(),o}document.addEventListener("click",async e=>{const t=e.target.closest(".rd-js-copy");if(!t||t.dataset.copyBusy)return;const o=getCopyText(t);if(!o)return;t.dataset.copyBusy="1";const a=()=>{t.dataset.icon=ICON_SUCCESS,clearTimeout(t._copyTimer),t._copyTimer=setTimeout(()=>{delete t.dataset.icon,delete t.dataset.copyBusy},1200)};try{await navigator.clipboard.writeText(o),a()}catch{fallbackCopy(o)?a():delete t.dataset.copyBusy}});function labelCopyIcons(){document.querySelectorAll(".rd-js-copy").forEach(e=>{!e.getAttribute("aria-label")&&!e.getAttribute("title")&&!e.textContent.trim()&&e.setAttribute("aria-label","Copy")})}document.readyState==="loading"?document.addEventListener("DOMContentLoaded",labelCopyIcons):labelCopyIcons();
